def reverse_integer(x: int) -> int:
    INT_MIN = -2**31
    INT_MAX = 2**31 - 1

    ans = 0

    def trunc_toward_zero_div_10(n: int) -> int:
        return n // 10 if n >= 0 else -((-n) // 10)

    while x != 0:
        q = trunc_toward_zero_div_10(x)
        digit = x - q * 10
        x = q

        if ans > INT_MAX // 10 or (ans == INT_MAX // 10 and digit > 7):
            return 0
        if ans < trunc_toward_zero_div_10(INT_MIN) or (ans == trunc_toward_zero_div_10(INT_MIN) and digit < -8):
            return 0

        ans = ans * 10 + digit

    return ans


# Alias for runners that expect a shorter LeetCode-style name.
def reverse(x: int) -> int:
    return reverse_integer(x)
